class MemoryManager:
    def __init__(self, total_size):
        self.total_size = total_size
        self.free_holes = [(0, total_size)]
        self.allocated = []

    def allocate(self, process_id, size):
        for i, (start, end) in enumerate(self.free_holes):
            hole_size = end - start
            if hole_size >= size:
                allocated_start = start
                allocated_end = start + size

                self.allocated.append({
                    'id': process_id,
                    'start': allocated_start,
                    'end': allocated_end
                })

                if hole_size == size:
                    self.free_holes.pop(i)
                else:
                    self.free_holes[i] = (allocated_end, end)

                return allocated_start
        return None

    def deallocate(self, process_id):
        for i, block in enumerate(self.allocated):
            if block['id'] == process_id:
                self.allocated.pop(i)
                self.free_holes.append((block['start'], block['end']))
                self.free_holes.sort()
                self.merge_holes()

    def merge_holes(self):
        if not self.free_holes:
            return
        merged = [self.free_holes[0]]
        for start, end in self.free_holes[1:]:
            if merged[-1][1] == start:
                merged[-1] = (merged[-1][0], end)
            else:
                merged.append((start, end))
        self.free_holes = merged

